#include<stdio.h>
main()
{
    int s,v1,v2,t1,t2;
    scanf("%d",&s);
    scanf("%d %d %d %d",&v1,&v2,&t1,&t2);

    int ans1=v1*s+2*t1;
    int ans2=v2*s+2*t2;

    if(ans1<ans2) printf("First\n");
    else if(ans1>ans2) printf("Second\n");
    else printf("Friendship\n");

    return 0;
}

