use std::error::Error;
use std::io;
use std::process;

fn main() {
    if let Err(e) = run() {
        println!("error: {}", e);
        process::exit(1);
    }
}

fn run() -> Result<(), Box<Error>> {
    let mut x = String::new();
    io::stdin().read_line(&mut x)?;
    let x: Vec<i32> = x.trim().split(" ").map(|x| x.parse().expect("")).collect();
    let a1 = x[0] * x[1] + x[3] * 2;
    let a2 = x[0] * x[2] + x[4] * 2;
    if a1 < a2 {
        println!("First");
    } else if a1 == a2 {
        println!("Friendship");
    } else {
        println!("Second");
    }
    Ok(())
}
